+        _errorMessage = null;
+        _shipment = null;
+        StateHasChanged();
+
+        try
+        {
+            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
+        }
+        catch (OperationCanceledException) when (ct.IsCancellationRequested)
+        {
+            // Navigation changed or component disposed — do nothing
+            return;
+        }
+        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
